import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import DropshippingExpandedContent, { DROPSHIPPING_EXPANDED_FAQS } from "@/components/DropshippingExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}


const FAQS = [
  { q: "What is a break-even point?", a: "The break-even point is the number of units you need to sell to exactly cover all your costs - fixed and variable. Any sales beyond this point generate profit." },
  { q: "What are fixed costs vs. variable costs?", a: "Fixed costs don't change with sales volume - rent, software subscriptions, salaries. Variable costs change per unit sold - materials, packaging, per-unit platform fees, shipping." },
  { q: "How do I calculate break-even revenue?", a: "Multiply your break-even units by your selling price. This gives you the total revenue needed to cover all costs. Our calculator shows this automatically." },
  { q: "What if my break-even point seems too high?", a: "Lower your fixed costs (cheaper tools, remove unused subscriptions), reduce cost per unit (negotiate with suppliers, buy in bulk), or raise your selling price. Even small margin improvements dramatically reduce break-even." },
  { q: "What is contribution margin?", a: "Contribution margin is the selling price minus the variable cost per unit. It represents how much each sale contributes to covering fixed costs. Once fixed costs are covered, the contribution margin becomes profit per unit." },
  { q: "How does break-even analysis help with pricing?", a: "Break-even analysis shows the minimum price needed to cover costs at a given volume. It reveals whether your current pricing can ever be profitable, and what price increase is needed if costs rise. It's essential before launching any product." },
  { q: "What is a good profit margin for dropshipping?", a: "Most dropshipping businesses aim for 20-40% profit margin after all costs (product, shipping, platform fees, advertising). Margins below 15% are difficult to sustain with paid advertising. Break-even analysis helps ensure your margins are viable." },
];

const EXPANDED_FAQS = DROPSHIPPING_EXPANDED_FAQS.breakEven;

export default function BreakEvenCalculator() {
  useCurrencyVersion();
  const [fixedCosts, setFixedCosts] = useState(2000);
  const [sellingPrice, setSellingPrice] = useState(49.99);
  const [costPerUnit, setCostPerUnit] = useState(18);

  const contributionMargin = sellingPrice - costPerUnit;
  const breakEvenUnits = contributionMargin > 0 ? Math.ceil(fixedCosts / contributionMargin) : 0;
  const breakEvenRevenue = breakEvenUnits * sellingPrice;
  const marginPct = sellingPrice > 0 ? (contributionMargin / sellingPrice) * 100 : 0;

  return (
    <>
      <SEOHead
        title="Free Break-Even Calculator Online - Find Your Break Even Point Instantly | CalcHive"
        description="Free online break-even calculator. Find the exact number of sales you need to cover your costs and start making profit. 100% free for businesses and dropshippers, no signup required."
        canonical="/break-even-calculator"
        keywords="free break even calculator, break even point calculator free online, calculate break even sales free, free business break even calculator, break even analysis tool free"
        category="Dropshipping"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/50 px-3 py-1 rounded-full mb-4">Dropshipping</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Break-Even Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free break even calculator to know exactly how many units you need to sell before making a profit. Enter your fixed costs, selling price, and variable cost per unit to calculate break even sales free in units and revenue. It works as a break even point calculator free online, a free business break even calculator, and a break even analysis tool free for any product launch or pricing decision.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="fixed-costs" label="Fixed Costs (monthly)" value={fixedCosts} min={0} max={100000} step={100} onChange={setFixedCosts} format={fmt} testId="input-fixed-costs" />
            <SliderInput id="selling-price-be" label="Selling Price" value={sellingPrice} min={1} max={1000} step={0.5} onChange={setSellingPrice} format={fmt} testId="input-selling-price" />
            <SliderInput id="cost-per-unit-be" label="Variable Cost Per Unit" value={costPerUnit} min={0} max={500} step={0.5} onChange={setCostPerUnit} format={fmt} testId="input-cost-per-unit" />
          </div>
          <motion.div key={`${fixedCosts}-${sellingPrice}-${costPerUnit}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            {contributionMargin > 0 ? (
              <>
                <div className="bg-gradient-to-br from-emerald-500 to-emerald-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                  <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Break-Even Point</p>
                  <p className="text-6xl font-black text-white tracking-tight" data-testid="result-units">{breakEvenUnits.toLocaleString()}</p>
                  <p className="text-white/70 text-sm mt-1">units to sell</p>
                </div>
                <div className="grid grid-cols-3 gap-3">
                  {[
                    { label: "Break-Even Revenue", value: fmt(breakEvenRevenue), testId: "result-revenue" },
                    { label: "Contribution Margin", value: fmt(contributionMargin) },
                    { label: "Margin %", value: `${marginPct.toFixed(1)}%` },
                  ].map(({ label, value, testId }) => (
                    <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                      <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                      <p className="text-lg font-extrabold text-foreground" data-testid={testId}>{value}</p>
                    </div>
                  ))}
                </div>
              </>
            ) : (
              <div className="bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800 rounded-2xl p-6 text-center">
                <p className="text-red-600 dark:text-red-400 font-bold">Selling price must be higher than cost per unit to calculate break-even.</p>
              </div>
            )}
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Break-Even Point for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Break-even analysis separates your costs into two types: fixed costs (constant regardless of sales) and variable costs (scale with each unit sold). The point where total revenue equals total costs is the break-even point. Every unit sold beyond this point generates pure profit.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Contribution Margin = Selling Price - Variable Cost Per Unit</p>
            <p>Break-Even Units = Fixed Costs  x  Contribution Margin</p>
            <p>Break-Even Revenue = Break-Even Units  x  Selling Price</p>
            <p>Profit at X Units = (X - Break-Even Units)  x  Contribution Margin</p>
          </div>
          <p className="text-muted-foreground leading-relaxed">Example: Fixed costs $2,000/month. Selling price $50. Variable cost $18. Contribution margin = $32. Break-even = 2,000  x  32 = 63 units. Revenue needed = 63  x  $50 = $3,125.</p>

          <h2 className="text-2xl font-bold text-foreground">How Many Sales Do You Need to Cover Your Costs</h2>
          {contributionMargin > 0 && (
            <div className="overflow-x-auto">
              <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
                <thead className="bg-muted/60">
                  <tr>
                    {["Units Sold", "Revenue", "Total Costs", "Profit / (Loss)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {[0.25, 0.5, 0.75, 1, 1.5, 2, 3].map(mult => {
                    const units = Math.round(breakEvenUnits * mult);
                    const revenue = units * sellingPrice;
                    const totalCosts = fixedCosts + units * costPerUnit;
                    const profit = revenue - totalCosts;
                    return (
                      <tr key={mult} className={`hover:bg-muted/30 ${mult === 1 ? "bg-emerald-50 dark:bg-emerald-950/20" : ""}`}>
                        <td className="py-2.5 px-4 font-semibold text-foreground">{units.toLocaleString()} {mult === 1 ? "(break-even)" : ""}</td>
                        <td className="py-2.5 px-4 text-muted-foreground">{fmt(revenue)}</td>
                        <td className="py-2.5 px-4 text-muted-foreground">{fmt(totalCosts)}</td>
                        <td className={`py-2.5 px-4 font-semibold ${profit >= 0 ? "text-emerald-600 dark:text-emerald-400" : "text-red-600 dark:text-red-400"}`}>{profit >= 0 ? "+" : ""}{fmt(profit)}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          <h2 className="text-2xl font-bold text-foreground">Free Break-Even Tool for Every Online Business</h2>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">Increase your selling price.</strong> A 10% price increase on a $50 product ($5 more) reduces break-even units by a disproportionately large amount when fixed costs are high relative to margin.</li>
            <li><strong className="text-foreground">Reduce variable costs.</strong> Negotiate with suppliers, buy in bulk, or switch to lower-cost shipping methods. Even $2 off per unit has a large cumulative effect.</li>
            <li><strong className="text-foreground">Cut unnecessary fixed costs.</strong> Audit subscriptions, software, and overhead monthly. Every $100 saved in fixed costs reduces your monthly break-even by approximately 3 units (at $32 contribution margin).</li>
            <li><strong className="text-foreground">Increase volume fast.</strong> Once past break-even, each additional unit is pure profit. Marketing that accelerates early sales velocity dramatically improves profitability.</li>
          </ul>
        </section>

        <DropshippingExpandedContent kind="breakEven" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/break-even-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


